struct Transaction: Codable, Identifiable {
    let id: UUID
    let type: TransactionType
    let amount: Decimal
    let currency: String
    let sourceAccountId: UUID?
    let destinationAccountId: UUID?
    let timestamp: Date
    var status: TransactionStatus
    let description: String
    let referenceNumber: String
    
    init(
        type: TransactionType,
        amount: Decimal,
        currency: String = "USD",
        sourceAccountId: UUID?,
        destinationAccountId: UUID?,
        description: String
    ) {
        self.id = UUID()
        self.type = type
        self.amount = amount
        self.currency = currency
        self.sourceAccountId = sourceAccountId
        self.destinationAccountId = destinationAccountId
        self.timestamp = Date()
        self.status = .pending
        self.description = description
        self.referenceNumber = Transaction.generateReferenceNumber()
    }
    
    private static func generateReferenceNumber() -> String {
        let timestamp = Int(Date().timeIntervalSince1970)
        var randomBytes = [UInt8](repeating: 0, count: 8)
        _ = SecRandomCopyBytes(kSecRandomDefault, randomBytes.count, &randomBytes)
        let randomHex = randomBytes.map { String(format: "%02x", $0) }.joined()
        return "TXN-\(timestamp)-\(randomHex.prefix(8).uppercased())"
    }
}

