// MARK: - Biometric Authentication Service

final class BiometricAuthService {
    
    enum AuthResult {
        case success
        case failure(Error)
        case notAvailable
    }
    
    static func authenticate(reason: String, completion: @escaping (AuthResult) -> Void) {
        let context = LAContext()
        context.localizedCancelTitle = "Cancel"
        
        var error: NSError?
        
        guard context.canEvaluatePolicy(.deviceOwnerAuthenticationWithBiometrics, error: &error) else {
            // Fall back to device passcode
            if context.canEvaluatePolicy(.deviceOwnerAuthentication, error: &error) {
                context.evaluatePolicy(.deviceOwnerAuthentication, localizedReason: reason) { success, evalError in
                    DispatchQueue.main.async {
                        if success {
                            completion(.success)
                        } else {
                            completion(.failure(evalError ?? BankingError.authenticationFailed))
                        }
                    }
                }
            } else {
                DispatchQueue.main.async {
                    completion(.notAvailable)
                }
            }
            return
        }
        
        context.evaluatePolicy(.deviceOwnerAuthenticationWithBiometrics, localizedReason: reason) { success, evalError in
            DispatchQueue.main.async {
                if success {
                    completion(.success)
                } else {
                    completion(.failure(evalError ?? BankingError.authenticationFailed))
                }
            }
        }
    }
}

// MARK: - Rate Limiter

final class RateLimiter {
    private var timestamps: [Date] = []
    private let maxRequests: Int
    private let timeWindow: TimeInterval
    private let queue = DispatchQueue(label: "com.bankingapp.ratelimiter")
    
    init(maxRequests: Int, timeWindowSeconds: TimeInterval) {
        self.maxRequests = maxRequests
        self.timeWindow = timeWindowSeconds
    }
    
    func allowRequest() -> Bool {
        queue.sync {
            let now = Date()
            timestamps = timestamps.filter { now.timeIntervalSince($0) < timeWindow }
            
            if timestamps.count < maxRequests {
                timestamps.append(now)
                return true
            }
            return false
        }
    }
}

