    private func executeTransfer(
        fromAccountId: UUID,
        toAccountId: UUID,
        amount: Decimal,
        description: String,
        completion: @escaping (Result<Transaction, BankingError>) -> Void
    ) {
        transactionQueue.sync(flags: .barrier) {
            do {
                guard InputValidator.isValidAmount(amount) else {
                    throw BankingError.invalidAmount
                }
                
                let sanitizedDescription = InputValidator.sanitizeString(description)
                
                guard var sourceAccount = accounts[fromAccountId] else {
                    throw BankingError.invalidAccount
                }
                
                guard var destAccount = accounts[toAccountId] else {
                    throw BankingError.invalidAccount
                }
                
                guard sourceAccount.status == .active else {
                    throw BankingError.accountLocked
                }
                
                guard destAccount.status == .active else {
                    throw BankingError.transactionFailed(reason: "Destination account is not active.")
                }
                
                let sourceBalance = sourceAccount.balance
                guard sourceBalance >= amount else {
                    throw BankingError.insufficientFunds
                }
                
                // Check daily limit on source
                sourceAccount.resetDailyLimitIfNeeded()
                guard sourceAccount.dailyTransactionTotal + amount <= Account.dailyTransactionLimit else {
                    throw BankingError.dailyLimitExceeded
                }
                
                var transaction = Transaction(
                    type: .transfer,
                    amount: amount,
                    sourceAccountId: fromAccountId,
                    destinationAccountId: toAccountId,
                    description: sanitizedDescription
                )
                
                let txHash = self.transactionHash(transaction)
                guard !recentTransactionHashes.contains(txHash) else {
                    throw BankingError.duplicateTransaction
                }
                
                // Atomic: debit source, credit destination
                let newSourceBalance = sourceBalance - amount
                let newDestBalance = destAccount.balance + amount
                
                try sourceAccount.setBalance(newSourceBalance)
                try destAccount.setBalance(newDestBalance)
                
                sourceAccount.dailyTransactionTotal += amount
                sourceAccount.lastTransactionDate = Date()
                destAccount.lastTransactionDate = Date()
                
                transaction.status = .completed
                accounts[fromAccountId] = sourceAccount
                accounts[toAccountId] = destAccount
                transactionHistory.append(transaction)
                recentTransactionHashes.insert(txHash)
                
                self.cleanOldTransactionHashes()
                
                auditLogger.log(
                    action: "TRANSFER",
                    accountId: fromAccountId,
                    transactionId: transaction.id,
                    result: "SUCCESS",
                    metadata: ["reference": transaction.referenceNumber]
                )
                
                completion(.success(transaction))
            } catch let error as BankingError {
                auditLogger.log(
                    action: "TRANSFER",
                    accountId: fromAccountId,
                    result: "FAILURE",
                    metadata: ["error": error.localizedDescription]
                )
                completion(.failure(error))
            } catch {
                auditLogger.log(
                    action: "TRANSFER",
                    accountId: fromAccountId,
                    result: "FAILURE",
                    metadata: ["error": error.localizedDescription]
                )
                completion(.failure(.transactionFailed(reason: error.localizedDescription)))
            }
        }
    }
    
    // MARK: - Helpers
    
    private func transactionHash(_ transaction: Transaction) -> String {
        let components = "\(transaction.type.rawValue)|\(transaction.amount)|\(transaction.sourceAccountId?.uuidString ?? "")|\(transaction.destinationAccountId?.uuidString ?? "")|\(Int(transaction.timestamp.timeIntervalSince1970 / 5))"
        return EncryptionService.hashData(components.data(using: .utf8)!)
    }
    
    private func cleanOldTransactionHashes() {
        // Keep set manageable; in production use time-based expiry
        if recentTransactionHashes.count > 10000 {
            recentTransactionHashes.removeAll()
        }
    }
}

// MARK: - Input Validator

struct InputValidator {
    
    static func isValidAmount(_ amount: Decimal) -> Bool {
        return amount > 0 && amount <= 1_000_000 && !amount.isNaN && amount.isFinite
    }
    
    static func isValidAccountNumber(_ accountNumber: String) -> Bool {
        let pattern = "^[0-9]{8,16}$"
        return accountNumber.range(of: pattern, options: .regularExpression) != nil
    }
    
    static func isValidName(_ name: String) -> Bool {
        let trimmed = name.trimmingCharacters(in: .whitespacesAndNewlines)
        guard trimmed.count >= 2 && trimmed.count <= 100 else { return false }
        let pattern = "^[a-zA-Z\\s\\-'.]+$"
        return trimmed.range(of: pattern, options: .regularExpression) != nil
    }
    
    static func sanitizeString(_ input: String) -> String {
        var sanitized = input.trimmingCharacters(in: .whitespacesAndNewlines)
        // Remove control characters
        sanitized = sanitized.unicodeScalars.filter { !$0.properties.isDefaultIgnorableCodePoint && ($0.value >= 32 || $0.value == 10) }
            .map { String($0) }
            .joined()
        // Limit length
        if sanitized.count > 500 {
            sanitized = String(sanitized.prefix(500))
        }
        return sanitized
    }
}

// MARK: - Currency Formatter

struct CurrencyFormatter {
    
    private static let formatter: NumberFormatter = {
        let formatter = NumberFormatter()
        formatter.numberStyle = .currency
        formatter.currencyCode = "USD"
        formatter.minimumFractionDigits = 2
        formatter.maximumFractionDigits = 2
        return formatter
    }()
    
    static func format(amount: Decimal, currencyCode: String = "USD") -> String {
        let localFormatter = formatter.copy() as! NumberFormatter
        localFormatter.currencyCode = currencyCode
        return localFormatter.string(from: amount as NSDecimalNumber) ?? "$0.00"
    }
}

// MARK: - Secure Network Configuration

struct SecureNetworkConfig {
    
    static func createSecureSession() -> URLSession {
        let config = URLSessionConfiguration.ephemeral
        config.tlsMinimumSupportedProtocolVersion = .TLSv12
        config.httpShouldSetCookies = false
        config.urlCache = nil
        config.requestCachePolicy = .reloadIgnoringLocalAndRemoteCacheData
        config.timeoutIntervalForRequest = 30
        config.timeoutIntervalForResource = 60
        
        return URLSession(configuration: config, delegate: SSLPinningDelegate(), delegateQueue: nil)
    }
}

final class SSLPinningDelegate: NSObject, URLSessionDelegate {
    
    // In production, store the actual certificate hashes
    private let pinnedCertificateHashes: Set<String> = [
        // Add SHA256 hashes of your server's certificates
    ]
    
    func urlSession(
        _ session: URLSession,
        didReceive challenge: URLAuthenticationChallenge,
        completionHandler: @escaping (URLSession.AuthChallengeDisposition, URLCredential?) -> Void
    ) {
        guard challenge.protectionSpace.authenticationMethod == NSURLAuthenticationMethodServerTrust,
              let serverTrust = challenge.protectionSpace.serverTrust else {
            completionHandler(.cancelAuthenticationChallenge, nil)
            return
        }
        
        // Evaluate server trust
        var error: CFError?
        let isValid = SecTrustEvaluateWithError(serverTrust, &error)
        
        guard isValid else {
            completionHandler(.cancelAuthenticationChallenge, nil)
            return
        }
        
        // In production, implement certificate pinning validation here
        // by comparing server certificate hash against pinnedCertificateHashes
        
        let credential = URLCredential(trust: serverTrust)
        completionHandler(.useCredential, credential)
    }
}

// MARK: - SwiftUI Views

import SwiftUI

struct AccountBalanceView: View {
    let accountId: UUID
    @State private var balance: String = "Loading..."
    @State private var transactions: [Transaction] = []
    @State private var errorMessage: String?
    @State private var showError = false
    @State private var showTransactionSheet = false
    @State private var accountName: String = ""
    @State private var maskedNumber: String = ""
    
    private let processor = TransactionProcessor.shared
    
    var body: some View {
        NavigationView {
            VStack(spacing: 0) {
                // Balance Card
                VStack(spacing: 8) {
                    Text(accountName)
                        .font(.headline)
                        .foregroundColor(.white.opacity(0.8))
                    
                    Text(maskedNumber)
                        .font(.caption)
                        .foregroundColor(.white.opacity(0.6))
                    
                    Text("Available Balance")
                        .font(.subheadline)
                        .foregroundColor(.white.opacity(0.7))
                    
                    Text(balance)
                        .font(.system(size: 36, weight: .bold, design: .rounded))
                        .foregroundColor(.white)
                }
                .frame(maxWidth: .infinity)
                .padding(.vertical, 32)
                .background(
                    LinearGradient(
                        gradient: Gradient(colors: [Color.blue, Color.blue.opacity(0.8)]),
                        startPoint: .topLeading,
                        endPoint: .bottomTrailing
                    )
                )
                .cornerRadius(16)
                .padding()
                
                // Action Buttons
                HStack(spacing: 20) {
                    ActionButton(title: "Deposit", systemImage: "arrow.down.circle.fill") {
                        showTransactionSheet = true
                    }
                    
                    ActionButton(title: "Withdraw", systemImage: "arrow.up.circle.fill") {
                        showTransactionSheet = true
                    }
                    
                    ActionButton(title: "Transfer", systemImage: "arrow.left.arrow.right.circle.fill") {
                        showTransactionSheet = true
                    }
                }
                .padding(.horizontal)
                
                // Transaction History
                VStack(alignment: .leading) {
                    Text("Recent Transactions")
                        .font(.headline)
                        .padding(.horizontal)
                        .padding(.top)
                    
                    if transactions.isEmpty {
                        VStack {
                            Spacer()
                            Text("No transactions yet")
                                .foregroundColor(.secondary)
                            Spacer()
                        }
                        .frame(maxWidth: .infinity)
                    } else {
                        List(transactions) { transaction in
                            TransactionRowView(transaction: transaction, currentAccountId: accountId)
                        }
                        .listStyle(.plain)
                    }
                }
            }
            .navigationTitle("Account")
            .navigationBarTitleDisplayMode(.inline)
            .onAppear(perform: loadAccountData)
            .alert("Error", isPresented: $showError) {
                Button("OK", role: .cancel) {}
            } message: {
                Text(errorMessage ?? "An unknown error occurred.")
            }
            .sheet(isPresented: $showTransactionSheet) {
                TransactionInputView(accountId: accountId) {
                    loadAccountData()
                }
            }
        }
    }
    
    private func loadAccountData() {
        do {
            let account = try processor.getAccount(id: accountId)
            accountName = account.accountHolderName
            maskedNumber = account.maskedAccountNumber
            balance = try processor.getFormattedBalance(accountId: accountId)
            transactions = try processor.getTransactionHistory(accountId: accountId)
        } catch {
            errorMessage = error.localizedDescription
            showError = true
        }
    }
}

struct ActionButton: View {
    let title: String
    let systemImage: String
    let action: () -> Void
    
    var body: some View {
        Button(action: action) {
            VStack(spacing: 8) {
                Image(systemName: systemImage)
                    .font(.title2)
                Text(title)
                    .font(.caption)
            }
            .frame(maxWidth: .infinity)
            .padding(.vertical, 12)
            .background(Color(.systemGray6))
            .cornerRadius(12)
        }
        .buttonStyle(.plain)
