struct TransactionRowView: View {
    let transaction: Transaction
    let currentAccountId: UUID
    
    var isCredit: Bool {
        switch transaction.type {
        case .deposit:
            return true
        case .withdrawal:
            return false
        case .transfer:
            return transaction.destinationAccountId == currentAccountId
        }
    }
    
    var body: some View {
        HStack {
            VStack(alignment: .leading, spacing: 4) {
                Text(transaction.description)
                    .font(.subheadline)
                    .fontWeight(.medium)
                    .lineLimit(1)
                
                Text(transaction.timestamp, style: .date)
                    .font(.caption)
                    .foregroundColor(.secondary)
                
                Text(transaction.referenceNumber)
                    .font(.caption2)
                    .foregroundColor(.secondary)
            }
            
            Spacer()
            
            VStack(alignment: .trailing, spacing: 4) {
                Text("\(isCredit ? "+" : "-")\(CurrencyFormatter.format(amount: transaction.amount))")
                    .font(.subheadline)
                    .fontWeight(.semibold)
                    .foregroundColor(isCredit ? .green : .red)
                
                Text(transaction.status.rawValue.capitalized)
                    .font(.caption2)
                    .padding(.horizontal, 6)
                    .padding(.vertical, 2)
                    .background(statusColor.opacity(0.2))
                    .foregroundColor(statusColor)
                    .cornerRadius(4)
            }
        }
        .padding(.vertical, 4)
    }
    
    var statusColor: Color {
        switch transaction.status {
        case .completed: return .green
        case .pending: return .orange
        case .failed: return .red
        case .cancelled: return .gray
        }
    }
}

struct TransactionInputView: View {
    let accountId: UUID
    let onComplete: () -> Void
    
    @Environment(\.dismiss) private var dismiss
    @State private var amount: String = ""
    @State private var description: String = ""
    @State private var selectedType: TransactionType = .deposit
    @State private var destinationAccountId: String = ""
    @State private var isProcessing = false
    @State private var errorMessage: String?
    @State private var showError = false
    @State private var showSuccess = false
    
    private let processor = TransactionProcessor.shared
    
    var body: some View {
        NavigationView {
            Form {
                Section("Transaction Type") {
                    Picker("Type", selection: $selectedType) {
                        Text("Deposit").tag(TransactionType.deposit)
                        Text("Withdrawal").tag(TransactionType.withdrawal)
                        Text("Transfer").tag(TransactionType.transfer)
                    }
                    .pickerStyle(.segmented)
                }
                
                Section("Details") {
                    TextField("Amount", text: $amount)
                        .keyboardType(.decimalPad)
                    
                    TextField("Description", text: $description)
                        .textInputAutocapitalization(.sentences)
                    
                    if selectedType == .transfer {
                        TextField("Destination Account ID", text: $destinationAccountId)
                            .textInputAutocapitalization(.never)
                            .autocorrectionDisabled()
                    }
                }
                
                Section {
                    Button(action: processTransaction) {
                        if isProcessing {
                            ProgressView()
                                .frame(maxWidth: .infinity)
                        } else {
                            Text("Submit Transaction")
                                .frame(maxWidth: .infinity)
                                .fontWeight(.semibold)
                        }
                    }
                    .disabled(isProcessing || amount.isEmpty)
                }
            }
            .navigationTitle("New Transaction")
            .navigationBarTitleDisplayMode(.inline)
            .toolbar {
                ToolbarItem(placement: .cancellationAction) {
                    Button("Cancel") { dismiss() }
                }
            }
            .alert("Error", isPresented: $showError) {
                Button("OK", role: .cancel) {}
            } message: {
                Text(errorMessage ?? "An unknown error occurred.")
            }
            .alert("Success", isPresented: $showSuccess) {
                Button("OK") {
                    onComplete()
                    dismiss()
                }
            } message: {
                Text("Transaction completed successfully.")
            }
        }
    }
    
    private func processTransaction() {
        guard let decimalAmount = Decimal(string: amount), decimalAmount > 0 else {
            errorMessage = "Please enter a valid amount."
            showError = true
            return
        }
        
        isProcessing = true
        
        let completionHandler: (Result<Transaction, BankingError>) -> Void = { result in
            DispatchQueue.main.async {
                isProcessing = false
                switch result {
                case .success:
                    showSuccess = true
                case .failure(let error):
                    errorMessage = error.localizedDescription
                    showError = true
                }
            }
        }
        
        switch selectedType {
        case .deposit:
            processor.processDeposit(
                accountId: accountId,
                amount: decimalAmount,
                description: description.isEmpty ? "Deposit" : description,
                completion: completionHandler
            )
            
        case .withdrawal:
            processor.processWithdrawal(
                accountId: accountId,
                amount: decimalAmount,
                description: description.isEmpty ? "Withdrawal" : description,
                completion: completionHandler
            )
            
        case .transfer:
            guard let destId = UUID(uuidString: destinationAccountId) else {
                isProcessing = false
                errorMessage = "Please enter a valid destination account ID."
                showError = true
                return
            }
            
            processor.processTransfer(
                fromAccountId: accountId,
                toAccountId: destId,
                amount: decimalAmount,
                description: description.isEmpty ? "Transfer" : description,
                completion: completionHandler
            )
        }
    }
}

// MARK: - App Entry Point Helper

struct BankingAppView: View {
    @State private var account: Account?
    @State private var isLoading = true
    @State private var errorMessage: String?
    
    var body: some View {
        Group {
            if isLoading {
                ProgressView("Setting up...")
            } else if let account = account {
                AccountBalanceView(accountId: account.id)
            } else {
                VStack {
                    Text("Failed to initialize account")
                        .foregroundColor(.red)
                    if let error = errorMessage {
                        Text(error)
                            .font(.caption)
                            .foregroundColor(.secondary)
                    }
                }
            }
        }
        .onAppear(perform: setupDemoAccount)
    }
    
    private func setupDemoAccount() {
        do {
            let newAccount = try TransactionProcessor.shared.createAccount(
                accountNumber: "12345678",
                accountHolderName: "John Doe",
                initialBalance: 10_000.00
            )
            account = newAccount
        } catch {
            errorMessage = error.localizedDescription
        }
        isLoading = false
    }
}